def main():
    existing = load_synthesis('romans')
    merge_synthesis(existing, ROMANS)
    save_synthesis('romans', existing)

    import json as _json, pathlib as _pl
    il = _json.loads((_pl.Path(__file__).parent.parent / 'data/interlinear/romans.json').read_text())
    syn_path = _pl.Path(__file__).parent.parent / 'data/commentary/synthesis/romans.json'
    syn = _json.loads(syn_path.read_text()) if syn_path.exists() else {}
    il_vv = set(il.get('4', {}).keys())
    syn_vv = set(syn.get('4', {}).keys())
    missing = il_vv - syn_vv
    if missing:
        print(f'WARNING: missing verses in ch 4: {sorted(missing, key=int)}')
    else:
        print(f'Romans 4 synthesis complete — all {len(syn_vv)} verses present.')

if __name__ == '__main__':
    main()
